import React, { useState } from 'react';

const App = () => {
  const [taskList, setTaskList] = useState([
    { id: 1, name: 'Task 1', complete: false },
    { id: 2, name: 'Task 2', complete: false },
    { id: 3, name: 'Task 3', complete: false }
  ]);
  const [searchQuery, setSearchQuery] = useState('');
  const [toggleComplete, setToggleComplete] = useState(false);

  const handleToggleComplete = (taskId) => {
    setTaskList(taskList.map((task) => {
      if (task.id === taskId) {
        return { ...task, complete: !task.complete };
      }
      return task;
    }));
  };

  const filteredTasks = taskList.filter((task) =>
    task.name.toLowerCase().includes(searchQuery.toLowerCase()) ||    task.complete === toggleComplete
  );

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-80 bg-white p-4 rounded shadow">
        <div className="mb-4">
          <input
            type="search"
            className="border border-gray-400 p-2 text-sm w-full"
            placeholder="Search Tasks"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
        <div className="mb-4">
          <input
            type="checkbox"
            className="mr-2"
            checked={toggleComplete}
            onChange={(e) => setToggleComplete(e.target.checked)}
          />
          <label>Toggle Complete</label>
        </div>
        <ul>
          {filteredTasks.map((task) => (
            <li key={task.id} className="mb-2">
              <span className="mr-2">{task.name}</span>
              <span className="text-sm text-gray-500">{task.complete ? ' Complete' : 'Incomplete'}</span>
              <button
                className="ml-2 bg-red-500 hover:bg-red-700 text-white font-bold py-1 px-2 rounded"
                onClick={() => handleToggleComplete(task.id)}
              >Toggle</button>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
